struct ECDSASignature {
    let r: Data
    let s: Data
    
    init?(signature: Data?) {
        guard let signature = signature else { return nil }
        
        let rStart = 0
        let rEnd = 32
        let sStart = 32
        let sEnd = 64
        
        self.r = signature.subdata(in: rStart..<rEnd)
        self.s = signature.subdata(in: sStart..<sEnd)
    }
    
    var hexString: String {
        return r.hexString + s.hexString
    }
}

